const items = $input.all();
const results = [];

for (const item of items) {
  const xmlData = item.json.data;

  // ✅ SR_NO COMES FROM MERGE NODE (NOT FROM TALLY)
  const srNo = item.json.SR_NO;
  const rowNumber = item.json.row_number;

  let status = "Failed";
  let errorMessage = "";

  if (
    xmlData.includes("<CREATED>1</CREATED>") &&
    !xmlData.includes("<EXCEPTIONS>1</EXCEPTIONS>")
  ) {
    status = "Posted";
  } else {
    const err = xmlData.match(/<LINEERROR>(.*?)<\/LINEERROR>/);
    if (err) errorMessage = err[1];
  }

  const vchIdMatch = xmlData.match(/<LASTVCHID>(\d+)<\/LASTVCHID>/);

  results.push({
    json: {
      SR_NO: srNo,                 // ✅ NOW ALWAYS PRESENT
      row_number: rowNumber,
      status,
      voucherId: vchIdMatch ? vchIdMatch[1] : "",
      errorMessage
    }
  });
}

return results;

const row = $input.item.json;

// --------------------
// IDENTIFIERS (n8n-only)
// --------------------
const srNo = row.SR_NO;
const rowNumber = row.row_number;
const tallyPort = row.Port || 9000;

// --------------------------------------------------
// XML Escape (Critical)
// --------------------------------------------------
function escapeXML(str) {
  return String(str || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");
}

// --------------------------------------------------
// Date Formatter (DD-MM-YYYY → YYYYMMDD)
// --------------------------------------------------
function formatDateForTally(input) {
  if (!input) throw new Error("VoucherDate is empty");
  const [dd, mm, yyyy] = String(input).split("-");
  if (!dd || !mm || !yyyy) throw new Error(`Invalid VoucherDate: ${input}`);
  return `${yyyy}${mm.padStart(2, "0")}${dd.padStart(2, "0")}`;
}

// --------------------------------------------------
// Safe Number
// --------------------------------------------------
function toNumber(val, fieldName = "Amount") {
  const num = Number(val);
  if (isNaN(num)) throw new Error(`Invalid ${fieldName}: ${val}`);
  return num;
}

// --------------------------------------------------
// Normalize Bill Type (🔥 FIX FOR ADVANCE)
// --------------------------------------------------
function normalizeBillType(type) {
  const t = String(type || "").trim().toLowerCase();

  if (t === "advance") return "New Ref";  // 🔥 Critical Fix
  if (t === "new ref") return "New Ref";
  if (t === "agst ref") return "Agst Ref";
  if (t === "on account") return "On Account";

  return "Agst Ref"; // Safe default
}

// --------------------------------------------------
// Bill Allocation XML Builder
// --------------------------------------------------
function buildBillXML(billNo, billAmount, billType, ledgerAmount, voucherAmount) {

  if (!billNo || !billAmount) {
    return `
    <BILLALLOCATIONS.LIST>
      <NAME>On Account</NAME>
      <BILLTYPE>On Account</BILLTYPE>
      <AMOUNT>${ledgerAmount}</AMOUNT>
    </BILLALLOCATIONS.LIST>`;
  }

  const billNos = String(billNo).split("|").map(b => b.trim());
  const billAmounts = String(billAmount).split("|").map(b => b.trim());
  const billTypes = String(billType || "Agst Ref")
    .split("|")
    .map(b => normalizeBillType(b.trim()));

  if (billNos.length !== billAmounts.length) {
    throw new Error("BillNo count does not match BillAmount count");
  }

  let billTotal = 0;
  let billXML = "";

  for (let i = 0; i < billNos.length; i++) {
    const amt = toNumber(billAmounts[i], "BillAmount");
    billTotal += amt;

    const finalAmt = ledgerAmount < 0 ? -amt : amt;

    billXML += `
    <BILLALLOCATIONS.LIST>
      <NAME>${escapeXML(billNos[i])}</NAME>
      <BILLTYPE>${escapeXML(billTypes[i] || "Agst Ref")}</BILLTYPE>
      <AMOUNT>${finalAmt}</AMOUNT>
    </BILLALLOCATIONS.LIST>`;
  }

  if (billTotal > voucherAmount) {
    throw new Error(
      `Bill total (${billTotal}) exceeds Voucher Amount (${voucherAmount})`
    );
  }

  const balance = voucherAmount - billTotal;

  if (balance > 0) {
    const finalBal = ledgerAmount < 0 ? -balance : balance;

    billXML += `
    <BILLALLOCATIONS.LIST>
      <NAME>On Account</NAME>
      <BILLTYPE>On Account</BILLTYPE>
      <AMOUNT>${finalBal}</AMOUNT>
    </BILLALLOCATIONS.LIST>`;
  }

  return billXML;
}

// --------------------------------------------------
// Ledger Entry Builder
// --------------------------------------------------
function buildLedgerEntry(
  ledgerName,
  amount,
  isDeemedPositive,
  narration = "",
  billData = null,
  voucherAmount = 0
) {

  let narrationXML = narration
    ? `<NARRATION>${escapeXML(narration)}</NARRATION>`
    : "";

  let billXML = "";

  if (billData) {
    billXML = buildBillXML(
      billData.billNo,
      billData.billAmount,
      billData.billType,
      amount,
      voucherAmount
    );
  }

  return `
  <ALLLEDGERENTRIES.LIST>
    <LEDGERNAME>${escapeXML(ledgerName)}</LEDGERNAME>
    ${narrationXML}
    <ISDEEMEDPOSITIVE>${isDeemedPositive}</ISDEEMEDPOSITIVE>
    <AMOUNT>${amount}</AMOUNT>
    ${billXML}
  </ALLLEDGERENTRIES.LIST>`;
}

// --------------------------------------------------
// Base Values
// --------------------------------------------------
const date = formatDateForTally(row.VoucherDate);
const voucherType = String(row.VoucherType).trim();
const company = row.Company;
const voucherNo = row.VoucherNo;
const narration = row.Narration || "";

// --------------------------------------------------
// Parse Ledgers
// --------------------------------------------------
const partyLedgers = String(row.PartyLedger).split("|").map(l => l.trim());
const counterLedgers = String(row.CounterLedger).split("|").map(l => l.trim());

// --------------------------------------------------
// Parse Amounts
// --------------------------------------------------
const amountStr = String(row.Amount).trim();
let partyAmounts = amountStr.includes("|")
  ? amountStr.split("|").map(a => Math.abs(toNumber(a)))
  : [Math.abs(toNumber(amountStr))];

if (partyLedgers.length !== partyAmounts.length) {
  throw new Error("Ledger count does not match Amount count");
}

const voucherAmount = partyAmounts.reduce((sum, amt) => sum + amt, 0);

// --------------------------------------------------
// Voucher Type Logic
// --------------------------------------------------
let partySign, counterSign, isContraXML = "";

if (voucherType === "Receipt") {
  partySign = 1;
  counterSign = -1;
}
else if (voucherType === "Payment") {
  partySign = -1;
  counterSign = 1;
}
else if (voucherType === "Contra") {
  partySign = -1;
  counterSign = 1;
  isContraXML = `<ISCONTRA>Yes</ISCONTRA>`;
}
else {
  throw new Error(`Unsupported VoucherType: ${voucherType}`);
}

// --------------------------------------------------
// Build Ledger Entries
// --------------------------------------------------
let allLedgerEntriesXML = "";

for (let i = 0; i < partyLedgers.length; i++) {

  const billData =
    voucherType !== "Contra" && i === 0
      ? {
          billNo: row.BillNo,
          billAmount: row.BillAmount,
          billType: row.BillType
        }
      : null;

  allLedgerEntriesXML += buildLedgerEntry(
    partyLedgers[i],
    partyAmounts[i] * partySign,
    partySign < 0 ? "Yes" : "No",
    "",
    billData,
    voucherAmount
  );
}

allLedgerEntriesXML += buildLedgerEntry(
  counterLedgers[0],
  voucherAmount * counterSign,
  counterSign < 0 ? "Yes" : "No"
);

// --------------------------------------------------
// FINAL XML
// --------------------------------------------------
return {
  xml: `<ENVELOPE>
  <HEADER>
    <TALLYREQUEST>Import Data</TALLYREQUEST>
  </HEADER>
  <BODY>
    <IMPORTDATA>
      <REQUESTDESC>
        <REPORTNAME>Vouchers</REPORTNAME>
        <STATICVARIABLES>
          <SVCURRENTCOMPANY>${escapeXML(company)}</SVCURRENTCOMPANY>
        </STATICVARIABLES>
      </REQUESTDESC>
      <REQUESTDATA>
        <TALLYMESSAGE xmlns:UDF="TallyUDF">
          <VOUCHER VCHTYPE="${voucherType}" ACTION="Create">
            <DATE>${date}</DATE>
            <EFFECTIVEDATE>${date}</EFFECTIVEDATE>
            <VOUCHERTYPENAME>${voucherType}</VOUCHERTYPENAME>
            ${isContraXML}
            <VOUCHERNUMBER>${escapeXML(voucherNo)}</VOUCHERNUMBER>
            <NARRATION>${escapeXML(narration)}</NARRATION>
            ${allLedgerEntriesXML}
          </VOUCHER>
        </TALLYMESSAGE>
      </REQUESTDATA>
    </IMPORTDATA>
  </BODY>
</ENVELOPE>`,

  SR_NO: srNo,
  row_number: rowNumber,
  Port: tallyPort
};
